class Solution { public: int findmax(vector<int>& piles) { int maxi = 0; for (int x : piles) maxi = max(maxi, x); return maxi; } long long calculatetotalhours(vector<int>& piles, int hourly) { long long totalhours = 0; for (int x : piles) { totalhours += (1LL * x + hourly - 1) / hourly; } return totalhours; } int minEatingSpeed(vector<int>& piles, int h) { int low = 1; int high = findmax(piles); while (low <= high) { int mid = low + (high - low) / 2; long long totalhours = calculatetotalhours(piles, mid); if (totalhours <= h) high = mid - 1; else low = mid + 1; } return low; } };